const QUESTS = {
  building: {
    title: "Building",
    subtitle: "The hearth becomes a citadel.",
    quests: [
      q("Hearth Claim", "Choose the heart of the future settlement and mark where the first hall will stand.", ["Walk the nearby area and choose the place where your long-term base will be built.", "Make sure it has room for expansion, nearby wood and stone, and a safe way back before dark.", "Mark the center with a campfire, pillar, torches, or banner.", "Clear the immediate ground so the first shelter can begin there."], "Pick somewhere practical first. Flat ground near trees, water, and surface stone is better than a dramatic place that is hard to defend.", "Surveyor's Kit", ["/give @p torch 16", "/give @p oak_log 16", "/give @p bread 8"]),
      q("First Shelter", "Raise the first refuge before the wilderness claims the night.", ["Build an enclosed shelter at least 5 blocks by 5 blocks inside.", "Add 4 walls, 1 roof, and 1 door or protected entrance.", "Make room inside for 1 bed, 1 crafting table, 1 furnace, and 1 chest.", "Survive 1 full night safely inside it."], "Dirt is acceptable for the first night, but wood or stone is better if you can gather it quickly.", "Settler's Bundle", ["/give @p oak_planks 32", "/give @p torch 16", "/give @p bread 8"]),
      q("Storehouse Corner", "Order is the first sign that a camp is becoming a home.", ["Place at least 3 chests inside or beside the shelter.", "Separate food, tools, and building blocks into different storage.", "Keep the storage area lit.", "Make sure you can reach supplies quickly in an emergency."], "Even simple organization makes hardcore survival much safer.", "Quartermaster's Gift", ["/give @p chest 3", "/give @p item_frame 3", "/give @p torch 12"]),
      q("Craftsman's Bench", "Every hall begins with the first honest workbench.", ["Place 1 crafting table inside the shelter or great hall.", "Craft 1 wooden pickaxe, 1 stone pickaxe, 1 stone axe, and 1 stone shovel.", "Place 1 furnace beside the crafting area.", "Store the starter tools in a chest or barrel marked for tools."], "This follows Minecraft's early advancement flow: punch logs, make planks, craft a table, then mine cobblestone for stone tools.", "Apprentice's Tools", ["/give @p crafting_table 1", "/give @p furnace 1", "/give @p cobblestone 32"]),
      q("Fire and Light", "Darkness is an enemy. Light is a claim upon the land.", ["Light the inside of the shelter so hostile mobs cannot spawn there.", "Light the entrance and nearby walking space outside.", "Remove obvious dark pockets around the base.", "Be able to step outside at night without immediate danger."], "Focus on the doorway, corners, and any holes or ledges nearby.", "Lamplighter's Cache", ["/give @p torch 32", "/give @p coal 16"]),
      q("The Great Hall Foundation", "The rough shelter must become the beginning of a true hall.", ["Expand the shelter into a main room at least 9 blocks by 9 blocks inside.", "Create 3 marked areas for sleeping, crafting, and storage.", "Improve at least 2 walls or the roof with wood, stone, beams, stairs, or slabs.", "Keep the entire structure safe with at least 8 light sources."], "This is the point where the base stops being temporary.", "Hallwright's Supplies", ["/give @p oak_log 24", "/give @p oak_planks 48", "/give @p lantern 4"]),
      q("Secure the Camp", "A wise ruler fortifies before decorating.", ["Mark the edge of your immediate base area.", "Add a fence, trench, wall, raised edge, or other defensive boundary.", "Create one clear entry point that you can defend.", "Light the approach to that entry point."], "You do not need a massive wall yet. Even a modest perimeter helps.", "Warden's Materials", ["/give @p cobblestone 64", "/give @p torch 16", "/give @p oak_fence 24"]),
      q("Lantern Road", "Roads bind a settlement together as surely as walls.", ["Choose 2 important places in the base, such as hall, farm, mine, smithy, or dock.", "Build a path at least 24 blocks long between them using 1 consistent style.", "Light the path with at least 6 torches, lanterns, or campfires.", "Remove every unlit gap longer than 7 blocks along the route."], "Even a 24-block road makes the whole base feel more like one settlement.", "Roadmaker's Stock", ["/give @p lantern 6", "/give @p gravel 32", "/give @p cobblestone 32"]),
      q("Walls of the Hearth", "The hearth deserves a boundary worthy of defense.", ["Expand the camp perimeter into a stronger town boundary.", "Build a more complete wall, fence line, or barrier.", "Add a gate or guarded entrance.", "Check that the wall links properly around the vulnerable edges."], "This wall does not need to be beautiful yet. It needs to keep the town feeling protected.", "Mason's Wages", ["/give @p stone_bricks 48", "/give @p cobblestone_wall 24", "/give @p torch 16"]),
      q("The Smithy Quarter", "No town can thrive without iron, flame, and tools in one place.", ["Choose a spot near the hall for a smithy or workshop wing.", "Build a room or yard for furnaces and metalworking.", "Place furnaces, ore storage, and tool storage there.", "Give it a distinct visual style so it feels like its own quarter."], "A smithy looks good with stone, brick, metal, or darker wood accents.", "Forgekeeper's Crate", ["/give @p iron_ingot 16", "/give @p coal 24", "/give @p blast_furnace 1"]),
      q("Hot Stuff Hearth", "A smithy becomes serious when it can command lava safely.", ["Craft or obtain 1 bucket.", "Collect 1 lava bucket without setting the town on fire.", "Build a stone-lined lava storage corner at least 3 blocks by 3 blocks.", "Place signs, walls, trapdoors, or barriers so Danita cannot accidentally walk into it."], "This is based on the Hot Stuff advancement. Make an iron bucket, find lava, then store it only in nonflammable blocks.", "Lavawright's Grant", ["/give @p bucket 1", "/give @p stone_bricks 32", "/give @p iron_ingot 8"]),
      q("Granary and Cellar", "A true town stores for winter, famine, and war.", ["Build a food storage room, pantry, cellar, or granary.", "Place barrels or chests for crops and cooked food.", "Move your food stock into that district.", "Decorate it so it feels like part of the settlement economy."], "Put this near fields, kitchen space, or the hall.", "Steward's Stores", ["/give @p barrel 4", "/give @p bread 16", "/give @p hay_block 12"]),
      q("Garden Court", "Beauty gives people a reason to endure hardship.", ["Pick an empty patch inside the settlement.", "Turn it into a courtyard, pond, herb patch, or decorative garden.", "Use at least 3 decorative materials, such as flowers, leaves, moss, or stone detail.", "Connect it to existing roads or entrances."], "A small beautiful space can make the base feel alive.", "Gardener's Satchel", ["/give @p flowering_azalea 2", "/give @p moss_block 16", "/give @p lantern 2"]),
      q("Town Main Square", "A true town needs a shared place where paths, bells, and people meet.", ["Choose a central open space at least 11 blocks by 11 blocks near the hall or main road.", "Flatten or frame the square with at least 64 path, stone, gravel, or slab blocks.", "Add 1 bell plus 4 lights, seats, stalls, fountain blocks, or notice board details.", "Connect at least 3 routes or districts to the square."], "Keep the square readable from above and from street level. A simple 11 by 11 stone or gravel plaza with lamps works well.", "Civic Founder's Grant", ["/give @p bell 1", "/give @p stone_bricks 32", "/give @p lantern 4"]),
      q("Library of Maps", "Roads are remembered by those who keep records.", ["Build a library, archive, or map room attached to the main base.", "Place bookshelves, storage, or lecterns inside it.", "Display at least one map, banner, or sign-based record.", "Reserve space for future exploration records."], "This room becomes much better later if you keep adding maps to it.", "Scholar's Chest", ["/give @p bookshelf 6", "/give @p lectern 1", "/give @p map 1", "/give @p paper 16"]),
      q("Enchanter's Corner", "Knowledge turns steel into legend when the hall learns to enchant.", ["Craft or obtain 1 enchanting table.", "Place it in the library, archive, or scholar wing.", "Surround it with at least 6 bookshelves.", "Enchant 1 tool, weapon, or armor piece and store it as Danita's first named relic."], "This follows the enchanting advancement route. You need diamonds, obsidian, a book, and lapis for the first enchantment.", "Arcane Scholar's Fund", ["/give @p lapis_lazuli 24", "/give @p bookshelf 8", "/give @p diamond 2"]),
      q("Stable of the North Road", "Long roads demand mounts, tack, and shelter.", ["Build a stable, paddock, or travel yard on one edge of the town.", "Include a place for at least one animal or future mount.", "Add storage for travel supplies and food.", "Connect the stable to a main road."], "Put the stable near the direction you most often travel.", "Stablemaster's Kit", ["/give @p saddle 1", "/give @p hay_block 16", "/give @p chest 1"]),
      q("Copper Workshop", "The town begins to show prosperity when craft becomes art.", ["Gather copper or use copper already stored.", "Build a workshop, roof section, tower top, or decorative wing with copper detail.", "Make sure it still matches the overall town style.", "Use the new structure as a real part of the settlement, not a disconnected decoration."], "Even a small amount of copper can make a build feel more advanced.", "Tinker's Treasury", ["/give @p copper_block 16", "/give @p lightning_rod 4", "/give @p lantern 4"]),
      q("Waxed Copper Sigil", "Copper craft becomes noble when the town learns to preserve its shine.", ["Place at least 8 copper blocks, cut copper blocks, or copper stairs in the workshop district.", "Collect at least 4 honeycomb.", "Wax at least 4 copper blocks with honeycomb.", "Leave 4 copper blocks unwaxed so Danita can see the difference over time."], "This is inspired by Wax On. Use honeycomb on copper to stop oxidation; use an axe later if you want to scrape wax or oxidation away.", "Preserved Copper Cache", ["/give @p honeycomb 6", "/give @p copper_block 12", "/give @p waxed_copper_block 4"]),
      q("The Villager Ward", "A settlement becomes a town when it shelters more than one soul.", ["Build a protected district for villagers.", "Add beds and at least one useful workstation.", "Make sure hostile mobs cannot easily enter at night.", "Keep the area fully lit and reachable from the rest of the base."], "The villager ward should feel like a defended neighborhood.", "Town Charter", ["/give @p bed 4", "/give @p bread 16", "/give @p bell 1"]),
      q("Living Town", "Let villagers truly live inside Danita's walls instead of merely surviving nearby.", ["Bring or protect at least two villagers inside the settlement.", "Give them safe beds, workstations, and a lit path to the town square or ward.", "Close holes, ledges, and gates that would let mobs reach them at night.", "Confirm the villagers can remain in town through a full night safely."], "Boats, minecarts, cured zombie villagers, or a nearby village can all solve the villager problem. The important part is a secure home, not the transport method.", "Mayor's Welcome", ["/give @p emerald 4", "/give @p bread 24", "/give @p lantern 4"]),
      q("Guest Hall", "A generous town keeps spare beds for travelers, allies, and future villagers.", ["Build a bunkhouse, inn room, or guest wing at least 7 blocks by 9 blocks connected to the settlement.", "Place 3 spare beds and at least 1 chest or barrel inside.", "Light the room with at least 4 light sources and give it 1 safe entrance from the main paths.", "Decorate it with at least 6 detail blocks so it feels welcoming rather than like overflow storage."], "Put guest beds near the square or hall if you want visitors to feel part of the town.", "Innkeeper's Bundle", ["/give @p bed 3", "/give @p chest 2", "/give @p lantern 3"]),
      q("Banner of the Ward", "Every district deserves a sign that it belongs to Danita's realm.", ["Choose one district, such as the villager ward, smithy, harbor, stable, or library.", "Craft or choose a banner color for that district.", "Place the banner at the district entrance or central building.", "Add a sign, item frame, or small detail that makes the district identity clear."], "Start simple. A single color banner over a gate can make a district feel official.", "Ward Banner Stipend", ["/give @p white_banner 2", "/give @p loom 1", "/give @p white_dye 4"]),
      q("Portal Wing", "Nether access should be a gate of purpose, not a hole in the ground.", ["Choose a proper place for Nether travel.", "Build a portal room, archway, or gatehouse.", "Add safe walking space, storage, and lighting around it.", "Make the portal feel like part of the town plan."], "Keep flammables and cramped corners away from the portal area.", "Embergate Provision", ["/give @p obsidian 10", "/give @p flint_and_steel 1", "/give @p fire_charge 4"]),
      q("Obsidian Frame", "The black stone of deep fire deserves a worthy threshold.", ["Mine or cast at least 10 obsidian.", "Build a complete Nether portal frame inside the portal wing.", "Add at least 8 nonflammable blocks around the frame as trim or safety floor.", "Light the portal only after the room is cleared and safe."], "This follows the portal-building progression. Use a diamond pickaxe to mine obsidian, or cast it with water and lava if you prefer the bucket method.", "Gate-Stone Cache", ["/give @p obsidian 6", "/give @p flint_and_steel 1", "/give @p crying_obsidian 2"]),
      q("The Hidden Exit", "A ruler who plans for disaster gives the town one road no enemy expects.", ["Choose a concealed place inside the base for an emergency exit.", "Dig or build a tunnel, back gate, water route, ladder shaft, or hidden path leading outside the walls.", "Light and secure the route so it can be used under pressure.", "Disguise or mark the entrance in a way Danita will remember."], "Do not make the tunnel so dark or confusing that it becomes its own danger. A secret exit still needs safe footing.", "Escape Cache", ["/give @p ladder 16", "/give @p torch 16", "/give @p iron_door 1"]),
      q("Harbor Steps", "Water is a road for those wise enough to use it.", ["Find 1 river, lake, or sea edge linked to your settlement.", "Build steps, a dock, or a landing at least 3 blocks wide and 7 blocks long.", "Add 1 chest or barrel for water travel or fishing gear.", "Connect the harbor to town paths with at least 16 path blocks or stairs."], "Even a 3 by 7 dock makes future travel feel intentional.", "Riverman's Bundle", ["/give @p oak_boat 1", "/give @p lantern 4", "/give @p barrel 2"]),
      q("Greenhouse Wing", "Delicate growth deserves shelter from frost and misfortune.", ["Build an enclosed farm room or greenhouse.", "Place crops inside it.", "Add lighting and water so it is functional.", "Blend it into the town rather than leaving it isolated."], "Glass, wood, and stone make an easy greenhouse palette.", "Glassgrower's Cache", ["/give @p glass 32", "/give @p dirt 16", "/give @p water_bucket 1"]),
      q("Kennel of Companions", "Loyal beasts deserve a place at the edge of the hall.", ["Build a kennel, pen, or companion corner.", "Include shelter, flooring, and access from a path.", "Add storage for food or supplies.", "Keep the enclosure safe from night danger."], "This works for wolves, cats, or decorative stable companions.", "Houndkeeper's Gift", ["/give @p bone 8", "/give @p cooked_beef 8", "/give @p carpet 4"]),
      q("Trial Hall Annex", "Let trophies and hard-won spoils become part of the town's memory.", ["Build a trophy room, armory, or war annex at least 7 blocks by 7 blocks.", "Add at least 2 armor stands, 2 banner spaces, or 4 item displays.", "Keep 1 chest or barrel for combat loot or dungeon supplies there.", "Display at least 1 named or memorable object from an expedition."], "This room becomes more fun the more adventures you survive.", "Relickeeper's Chest", ["/give @p armor_stand 2", "/give @p item_frame 4", "/give @p white_banner 2"]),
      q("Brewer's Alcove", "The hall should keep more than blades for dangerous roads.", ["Build a brewing alcove at least 5 blocks by 5 blocks inside the hall, library, or war annex.", "Place 1 brewing stand, 1 water source, and 1 chest or barrel for ingredients.", "Brew at least 1 potion of any type.", "Store 3 glass bottles or finished potions in the alcove."], "This follows the brewing progression. A brewing stand needs blaze rods, bottles need glass, and Nether wart starts most useful potion recipes.", "Alchemist's Reserve", ["/give @p brewing_stand 1", "/give @p glass_bottle 6", "/give @p nether_wart 8"]),
      q("Archaeologist's Yard", "Ancient fragments deserve study, not a random chest.", ["Build a relic yard, dig shed, or archaeology room.", "Add shelves, pots, or display pedestals.", "Create storage for brushes, pottery shards, or suspicious block finds.", "Place at least one decorative relic display."], "This room pairs well with maps, signs, and pots.", "Dust-Seeker's Crate", ["/give @p brush 1", "/give @p decorated_pot 2", "/give @p chest 1"]),
      q("Hall of Maps and Banners", "Every frontier town should proclaim where it has been and what it has survived.", ["Expand your map room or build a dedicated hall for travel records.", "Hang at least two maps, banners, or route markers.", "Add a display for named expeditions or known landmarks.", "Make the hall feel like a civic record of the settlement."], "Use signs to name regions, roads, or dangers.", "Chronicler's Award", ["/give @p map 2", "/give @p white_banner 2", "/give @p glow_item_frame 2"]),
      q("Copper Clocktower", "A skyline landmark gives the town identity and warning alike.", ["Build a tower taller than the surrounding structures.", "Use copper or other advanced detail on the upper section.", "Add a lit top, bell, or signal point.", "Make sure it can be safely reached from the ground."], "A good tower becomes the visual symbol of the settlement.", "Watchmaker's Grant", ["/give @p copper_block 24", "/give @p bell 1", "/give @p lantern 6"]),
      q("Sky Dock", "The upper reaches of the settlement should be ready for lookout duty and future travel.", ["Choose a high point in or above the base.", "Build a platform, terrace, or elevated landing area.", "Connect it safely with stairs, scaffolding, or protected climbing.", "Add rails, lighting, and storage."], "Think of this as both lookout and prestige structure.", "Highroad Supply", ["/give @p scaffolding 32", "/give @p lantern 10", "/give @p chest 2", "/give @p emerald 4"]),
      q("Sculk-Sealed Vault", "Deep relics and dangerous treasures require a chamber of secrecy.", ["Choose a secure location for rare items.", "Build a hidden, fortified, or isolated vault room.", "Add doors, locks, or redstone-style access if desired.", "Move your rarest loot into the vault."], "This is the symbolic late-game treasure room.", "Vaultwarden's Seal", ["/give @p iron_door 2", "/give @p redstone_torch 8", "/give @p diamond 3", "/give @p echo_shard 2"]),
      q("Pale Garden Watchpost", "A road into eerie lands should be watched and warded.", ["Choose the outer edge of your territory facing a dangerous region.", "Build a watchpost, guard hut, or outlying gate.", "Link it back to town with a safe route or marked path.", "Add lighting and supplies for a return stop."], "This should feel like a frontier post, not a second town.", "Sentinel's Store", ["/give @p campfire 2", "/give @p lantern 4", "/give @p spruce_log 24"]),
      q("Pale Gate Chapel", "Let the edge of the realm bear a solemn shrine against darkness.", ["Build a shrine, chapel, or memorial near a gate or road edge.", "Use pale, mossy, or quiet decorative materials if possible.", "Add candles, benches, or symbolic detail.", "Make the structure feel intentional and solemn."], "This quest is about mood as much as function.", "Warden Chapel Fund", ["/give @p candle 8", "/give @p quartz_block 16", "/give @p lantern 4"]),
      q("Hill Shrine", "A nearby height should hold a quiet place for vows, memory, and watchfulness.", ["Find 1 hill or mountain within 300 blocks of the settlement.", "Build a shrine, altar, cairn, or chapel at least 5 blocks by 5 blocks on the high ground.", "Create a safe path, stair, or marked climb with at least 12 markers or stair blocks.", "Add at least 4 candles, flowers, banners, bells, or view-facing platform details."], "Choose a hill that feels connected to the town. The shrine should be a destination, not a random decoration in the distance.", "Pilgrim's Offering", ["/give @p candle 8", "/give @p stone_bricks 24", "/give @p white_banner 1"]),
      q("Vault of Relics", "Rare treasures should become memory, not vanish into unsorted chests.", ["Choose a protected display room or expand the existing vault.", "Place item frames, armor stands, pots, or pedestals for rare finds.", "Display at least three meaningful items from Danita's journey.", "Keep the room secure, lit, and connected to the settlement story."], "Display copies or less risky trophies if you are nervous about losing valuables. The point is to make achievements visible.", "Relic Display Fund", ["/give @p item_frame 8", "/give @p armor_stand 2", "/give @p glow_item_frame 4", "/give @p diamond 2"]),
      q("Citadel Crown", "The final mark of mastery is a structure that declares the settlement complete.", ["Choose the final prestige project for the base.", "Build a keep roofline, monument, central tower crown, or similar capstone structure.", "Make it visible from the rest of town.", "Finish it as a statement that the settlement has become a citadel."], "This is your end of the building path landmark.", "Lord's Treasury", ["/give @p diamond 8", "/give @p emerald 16", "/give @p copper_block 32", "/give @p netherite_upgrade_smithing_template 1"])
    ]
  },
  gathering: {
    title: "Gathering",
    subtitle: "The storehouse fills before the banners rise.",
    quests: [
      q("The First Stores", "Before glory comes stockpile.", ["Gather 1 stack of logs, 1 stack of cobblestone, and 32 coal or charcoal.", "Bring all 160 items back to the shelter.", "Store them in a chest instead of carrying everything at once.", "Keep 16 torches and 8 food items as an emergency supply."], "Early survival is safer when the base already has counted materials.", "Pioneer's Wage", ["/give @p bread 12", "/give @p torch 16", "/give @p chest 1"]),
      q("Bread for the Hall", "A warm hall is meaningless if the table is bare.", ["Gather or cook 32 total food items.", "Turn at least 16 of those items into bread, cooked meat, baked potatoes, or another ready-to-eat food.", "Put 24 food items into base storage.", "Keep 8 food items on Danita for emergencies."], "Bread, cooked meat, or early farm crops all count if the total reaches 32 food items.", "Baker's Due", ["/give @p bread 16", "/give @p wheat 24"]),
      q("Timber Tithe", "The forest pays the first tax to every new settlement.", ["Chop 2 stacks of logs for future building work.", "Bring all 128 logs safely back to the base.", "Replant at least 8 saplings if you have them.", "Store at least 96 logs for building instead of spending them on tools."], "Two full stacks now make the first hall expansion much easier later.", "Woodcutter's Thanks", ["/give @p oak_log 24", "/give @p torch 8"]),
      q("Orchard Row", "A wise settlement plants tomorrow's wood and fruit before the old trees are gone.", ["Choose a clear strip of land at least 3 blocks wide and 16 blocks long near the base.", "Plant at least 8 saplings in a row or small grove.", "Leave at least 4 blocks between each sapling so the trees can grow and be harvested safely.", "Place at least 8 torches or fence the area if it sits outside the main wall."], "Oak, birch, spruce, jungle, cherry, or other saplings all work. Keep the orchard close enough that replanting becomes a habit.", "Orchard Keeper's Gift", ["/give @p oak_sapling 8", "/give @p bone_meal 16", "/give @p torch 8"]),
      q("Stone for the Hearth", "Timber raises a camp. Stone raises a future.", ["Mine 2 stacks of stone or cobblestone close to the base.", "Bring back all 128 stone blocks for walls, paths, or furnaces.", "Store at least 96 stone blocks in your building materials chest.", "Keep 32 stone blocks untouched for the next building project."], "Surface stone, shallow cave stone, or smelted stone all fit the spirit.", "Quarryman's Pay", ["/give @p cobblestone 48", "/give @p coal 12"]),
      q("Fields of Plenty", "The land nearest the hall should feed the hall.", ["Plant a crop field with at least 32 tilled farmland blocks near the base.", "Use water so every crop is within 4 blocks of a water source.", "Harvest at least 24 crops from the field.", "Store 16 harvested crops in food storage."], "Wheat, potatoes, and carrots make a strong early farm set.", "Farmer's Blessing", ["/give @p wheat_seeds 16", "/give @p carrot 12", "/give @p potato 12"]),
      q("Iron for the Forge", "Every useful thing in early survival asks for iron.", ["Go mining specifically for at least 24 raw iron.", "Return alive with the 24 raw iron or iron ore.", "Smelt at least 16 iron ingots or store the raw iron in smithy supplies.", "Keep 8 iron ingots unused for future tools and gear."], "Do not spend it all immediately. The point is building stock.", "Smith's Wages", ["/give @p iron_ingot 12", "/give @p coal 16"]),
      q("Acquire Hardware", "The first iron ingot marks the settlement's step beyond stone.", ["Mine at least 8 raw iron.", "Smelt at least 8 iron ingots.", "Craft 1 iron pickaxe or 1 iron axe.", "Store 4 iron ingots in the smithy instead of spending everything."], "This mirrors the Acquire Hardware advancement. Mine iron ore, smelt it in a furnace, then keep a small reserve for future tools.", "Ironworker's Purse", ["/give @p iron_ingot 12", "/give @p coal 16", "/give @p raw_iron 8"]),
      q("Glassmaker's Burden", "Sand becomes windows, lantern frames, and civilized ambition.", ["Gather 1 stack of sand.", "Smelt at least 48 sand into glass.", "Store 32 glass blocks for a future building quest.", "Keep 16 glass blocks unused for later windows or greenhouse work."], "This quest supports greenhouse, windows, and decorative upgrades.", "Glazier's Purse", ["/give @p glass 24", "/give @p coal 12"]),
      q("Leather and Reed", "Books, maps, and knowledge begin in humble materials.", ["Gather at least 8 leather from animals or loot.", "Harvest or grow at least 32 sugar cane.", "Bring all leather and sugar cane back to storage.", "Keep 8 leather and 24 sugar cane ready for books, maps, or library work."], "This prepares you for map room and enchantment progress.", "Scribe's Bundle", ["/give @p leather 8", "/give @p sugar_cane 24", "/give @p paper 12"]),
      q("River Reed Contract", "A steward who neglects paper neglects the memory of the realm.", ["Find a riverbank or water edge within a safe route from home.", "Harvest at least 64 sugar cane.", "Replant at least 16 sugar cane beside water.", "Store 48 sugar cane or 48 paper in the scholar quarter."], "This is your long-term map and book supply quest.", "Recordkeeper's Roll", ["/give @p paper 24", "/give @p sugar_cane 24"]),
      q("Beekeeper's Tithe", "Honey and flowers soften a hard life and serve more than beauty.", ["Find bees or 1 bee nest.", "Collect 3 honey bottles or 6 honeycomb safely.", "Bring back 8 flowers or related decorative goods.", "Store all bee products in food, garden, or trade storage."], "Campfires help when working around bees.", "Apiarist's Share", ["/give @p honey_bottle 3", "/give @p honeycomb 6"]),
      q("Bee Our Guest", "The garden becomes kinder when bees work beside the hall.", ["Place 1 campfire under a bee nest or beehive.", "Use 1 glass bottle to collect honey without angering the bees.", "Plant at least 8 flowers within 16 blocks of the hive.", "Store 1 honey bottle or 3 honeycomb in garden storage."], "This is based on Bee Our Guest. Smoke calms the hive; use bottles for honey and shears for honeycomb.", "Honeyed Favor", ["/give @p honey_bottle 4", "/give @p honeycomb_block 2", "/give @p flowering_azalea 2"]),
      q("Mounted Provisioning", "Long travel begins with simple preparation.", ["Gather 16 cooked food items for expeditions.", "Bring back 8 leather and 8 hay blocks or stable-friendly materials.", "Store all travel supplies in the stable or road supplies chest.", "Leave at least 8 food items and 4 hay blocks ready for future journeys."], "This supports road and mount-themed quests later.", "Roadwarden's Pouch", ["/give @p cooked_beef 12", "/give @p hay_block 8", "/give @p leather 4"]),
      q("Barnyard Compact", "The town's food supply grows stronger when animals have a proper home.", ["Build or claim safe pens for 2 cows, 2 pigs, 4 chickens, and 1 horse if available.", "Bring the animals into or beside the settlement without leaving them exposed to mobs.", "Add at least 4 gates, 12 torches, and 1 feed chest.", "Breed at least 2 animals or store 16 feed items for later breeding."], "Use wheat for cows, seeds for chickens, carrots or potatoes for pigs, and fenced space for horses. Keep pens simple until the town can afford a larger barn.", "Husbandry Grant", ["/give @p wheat 16", "/give @p carrot 12", "/give @p wheat_seeds 16"]),
      q("The Copper Cache", "The town enters a richer age when copper enters the ledger.", ["Mine at least 64 raw copper.", "Smelt at least 48 copper ingots.", "Store all 48 ingots in building stock.", "Keep 32 copper ingots reserved for decorative or advanced construction."], "Copper is best used as future town material, not wasted immediately.", "Tinker's Fee", ["/give @p copper_ingot 24", "/give @p coal 12"]),
      q("Wool for the Hall", "Comfort is not weakness when winter comes.", ["Gather at least 32 wool through sheep, shears, or dyes.", "Bring back 24 wool for decoration, beds, or banners.", "Store all wool separately from stone and wood.", "Keep 16 wool as a cloth reserve for future building interiors."], "A base feels much more settled once interiors use wool or banners.", "Weaver's Gift", ["/give @p white_wool 16", "/give @p red_wool 8"]),
      q("Shepherd's Pen", "A steady wool supply begins with a safe flock.", ["Build a sheep enclosure at least 7 blocks by 7 blocks within 50 blocks of the base.", "Bring at least 2 sheep into the pen or prepare it for them.", "Add 1 gate, 8 torches, and at least 25 grass blocks for the sheep to regrow wool.", "Collect at least 16 wool by color, quantity, or future banner needs."], "Keep shears and dye storage nearby. A 7 by 7 grass pen is more useful than a huge empty pasture.", "Shepherd's Bundle", ["/give @p shears 1", "/give @p white_wool 12", "/give @p wheat 12"]),
      q("Spring to Life Harvest", "Bring home flowers, leaves, and wild beauty from nearby lands.", ["Travel to 1 nearby biome different from the base biome.", "Gather at least 3 material types and 32 total decorative natural blocks or items.", "Return all 32 items safely to base.", "Store 24 items for landscaping or garden work."], "Moss, flowers, leaves, and saplings all help the town look more alive.", "Herbalist's Satchel", ["/give @p moss_block 16", "/give @p azalea 2", "/give @p flowering_azalea 2"]),
      q("Glow Berry Descent", "Caves hide living lanterns for those willing to descend.", ["Find 1 lush cave or cave-vine source.", "Gather at least 16 glow berries and 12 moss or cave greenery blocks.", "Return to base alive with all gathered items.", "Store 16 glow berries for gardens, kitchens, or hall decoration."], "This quest is a cave run with decorative purpose.", "Cavern Tender's Prize", ["/give @p glow_berries 16", "/give @p moss_block 12"]),
      q("Deep Quarry", "Great walls demand greater stone.", ["Mine 4 stacks of stone, deepslate, or masonry material.", "Bring all 256 blocks back in one or more safe trips.", "Sort the materials into building stock.", "Keep at least 3 stacks available for major projects."], "This is your big construction reserve quest.", "Mason's Dividend", ["/give @p stone 64", "/give @p andesite 32"]),
      q("Glow in the Dark", "The larger the town, the more light it devours.", ["Gather 32 coal or charcoal and 64 sticks, or equivalent lantern materials.", "Craft at least 64 torches or 12 lanterns.", "Store all light sources in the base for future defenses and roads.", "Keep at least 32 torches untouched for expansion."], "Running out of light is one of the easiest ways to make a town unsafe.", "Lightbearer's Cache", ["/give @p torch 32", "/give @p lantern 6", "/give @p coal 24"]),
      q("Pearls for the Future", "The wise keep part of their gaze turned toward the End.", ["Prepare 16 food items and a safe return route.", "Hunt or gather at least 2 ender pearls or similar rare progression loot.", "Return alive with the pearls or rare loot.", "Store 2 pearls in a vault or rare-goods chest."], "This quest is about long-term progression readiness.", "Wayfarer's Token", ["/give @p ender_pearl 2", "/give @p golden_carrot 8"]),
      q("Diamond Ledger", "The treasury changes when Danita brings home the first true gems.", ["Mine or loot at least 2 diamonds.", "Return to town alive with both diamonds.", "Store 1 diamond in the vault or rare-goods chest.", "Use or reserve the second diamond for enchanting, tools, or town upgrades."], "This follows the diamond milestone. Search deep caves or branch mines at diamond levels, carry water, and leave when you have the gems.", "Gemfinder's Reward", ["/give @p diamond 3", "/give @p emerald 4", "/give @p lapis_lazuli 16"]),
      q("Armadillo Scute Run", "Loyal companions deserve more than courage alone.", ["Travel to 1 savanna or badlands biome.", "Find at least 1 armadillo.", "Collect at least 6 scutes from the journey.", "Return all scutes to your kennel, vault, or smithy storage."], "Think of this as a specialty material expedition for companion gear.", "Beastwarden's Satchel", ["/give @p armadillo_scute 6", "/give @p bone 6"]),
      q("Pottery Shard Hunt", "Dust and buried memory are treasure to patient hands.", ["Craft or bring 1 brush.", "Travel to 1 archaeology site.", "Find suspicious sand or suspicious gravel.", "Brush at least 1 suspicious block without breaking it.", "Return with 1 shard, relic, or archaeology item."], "Desert wells, desert temples, trail ruins, and some ocean ruins are good targets.", "Antiquarian's Purse", ["/give @p brush 1", "/give @p decorated_pot 1", "/give @p emerald 2"]),
      q("Trial Chamber Provisions", "No delver should descend into danger with a half-packed kit.", ["Prepare 16 strong food items, 32 arrows, 64 blocks, and 2 spare tools.", "Create 1 dedicated expedition chest or travel loadout.", "Leave 1 backup weapon, 1 backup pickaxe, and 8 food items at home in case of loss.", "Finish with 1 complete dungeon-ready kit."], "This is not the chamber run itself. It is the preparation that makes it survivable.", "Delver's Loadout", ["/give @p arrow 24", "/give @p cooked_beef 12", "/give @p cobblestone 32"]),
      q("Tuff and Copper Reserve", "Richer architecture begins in deeper strata.", ["Gather 64 tuff and 32 copper ingots or 8 copper blocks from underground exploration.", "Bring both resources back alive.", "Store all tuff and copper in building stock.", "Keep at least 48 tuff and 8 copper blocks reserved for advanced construction."], "This supports your more impressive mid-late building quests.", "Stonewright's Grant", ["/give @p tuff 32", "/give @p copper_block 8"]),
      q("Sculk Sample Recovery", "Bring back the strange growth of the deep without becoming part of it.", ["Prepare 16 food items, 32 wool, and a marked escape route for a dangerous underground run.", "Reach 1 sculk-rich area.", "Gather at least 16 sculk blocks or related deep materials.", "Escape and return with all 16 sample blocks."], "This is a tense extraction quest, not a long stay.", "Deep Scholar's Fee", ["/give @p sculk 16", "/give @p diamond 1"]),
      q("Breeze-Proof Supplies", "Strange new dangers demand sensible preparation.", ["Gather 1 shield, 16 food items, 32 arrows, and 2 spare equipment pieces.", "Build 1 reliable dungeon loadout meant for knockback-heavy combat.", "Store that loadout in 1 labeled chest.", "Keep the full loadout ready for Trial Chamber work."], "This is another prep quest, but more specialized than the earlier chamber provisions quest.", "Chamberrunner's Bag", ["/give @p shield 1", "/give @p arrow 24", "/give @p cooked_beef 12"]),
      q("Fisher's Tribute", "Rivers and coasts should feed the hall as surely as fields.", ["Go on 1 fishing or shoreline supply trip.", "Bring back 16 fish or 1 water-related treasure item.", "Store the catch in food or harbor supplies.", "Leave at least 10 cooked fish or 1 fishing rod in harbor storage."], "This quest fits especially well once you have a dock.", "Rivertithe", ["/give @p cooked_cod 10", "/give @p salmon 6", "/give @p fishing_rod 1"]),
      q("Fishy Business", "A quiet catch can feed the hall without risking a blade.", ["Craft or obtain 1 fishing rod.", "Catch at least 5 fish from river, lake, or ocean water.", "Cook at least 3 fish or store them raw in food storage.", "Keep the fishing rod in harbor or food supplies."], "This is based on Fishy Business. Cast a fishing rod into open water and wait for the bobber to dip before reeling in.", "Angler's Pay", ["/give @p fishing_rod 1", "/give @p cooked_cod 12", "/give @p prismarine_crystals 4"]),
      q("Tactical Fishing", "Some catches are better carried alive.", ["Craft or obtain 1 bucket.", "Use the bucket on a fish in water to capture it alive.", "Bring the fish bucket back to town.", "Release it into a pond, harbor, aquarium, or garden water feature."], "This follows Tactical Fishing. Hold a water bucket, get close to a fish, and use the bucket on the fish itself.", "Live Catch Bonus", ["/give @p bucket 1", "/give @p tropical_fish_bucket 1", "/give @p sea_lantern 2"]),
      q("Vaultkeeper's Reserve", "The settlement now keeps not just supplies, but emergency wealth.", ["Gather 2 diamonds, 4 emeralds, 2 ender pearls, or 8 golden carrots as rare goods.", "Return and store all rare goods in the vault.", "Keep those items as reserve wealth, not daily use items.", "Finish with at least 8 rare or advanced items stored as strategic surplus."], "This is your final economic maturity quest.", "Treasury Allotment", ["/give @p diamond 5", "/give @p emerald 12", "/give @p golden_carrot 16", "/give @p amethyst_block 8"])
    ]
  },
  pathfinder: {
    title: "Pathfinder",
    subtitle: "The frontier opens under steady feet.",
    quests: [
      q("A Place to Call Home", "Before walls are raised, a survivor must choose where to stand.", ["Explore at least 300 blocks around spawn or your starting point.", "Find a base location with at least 32 by 32 blocks of usable build space, nearby wood, and nearby stone.", "Mark that location with 1 pillar, 1 campfire, or 4 torches so you can return reliably.", "Get back safely with the choice made."], "Near water, wood, and open building room is ideal.", "Wayfinder's Start", ["/give @p compass 1", "/give @p bread 8", "/give @p torch 12"]),
      q("Scout the Perimeter", "Learn the land before the land teaches you the hard way.", ["Walk a loop at least 150 blocks out from the chosen base location.", "Identify 1 wood source, 1 stone source, 1 water source, and 1 food source.", "Mark or remember at least 2 danger spots such as caves, cliffs, ravines, or mob-heavy areas.", "Return to base with a clear idea of the immediate terrain."], "This quest is about knowledge, not loot.", "Ranger's Notes", ["/give @p map 1", "/give @p torch 12"]),
      q("Night Watch", "The first enemies should fall before they ever touch the walls.", ["Wait until night within 50 blocks of the base.", "Patrol the outer edge of your settlement for 1 full night cycle.", "Defeat at least 5 hostile mobs near your territory.", "Return inside safely before the situation becomes reckless."], "Stay near home. This is defense, not a midnight expedition.", "Watchman's Share", ["/give @p arrow 16", "/give @p shield 1"]),
      q("Not Today", "A shield turns a desperate hit into a controlled answer.", ["Craft or obtain 1 shield.", "Find 1 skeleton, pillager, or other ranged threat.", "Block at least 1 projectile with the shield.", "Return to town with the shield still in Danita's inventory."], "This is based on the shield deflection advancement. Equip a shield, hold block before the arrow lands, then retreat before the fight spreads.", "Shieldmaiden's Due", ["/give @p shield 1", "/give @p iron_ingot 8", "/give @p arrow 16"]),
      q("The Road Beyond", "The future of the town lies beyond what it can already see.", ["Leave the base with 12 food items, 16 torches, and 8 blocks or signs for route markers.", "Travel at least 500 blocks or until you discover 1 new biome, landmark, or notable resource area.", "Mark the way with at least 4 signs, torch pillars, block markers, or map notes.", "Return alive with route knowledge or 1 useful find."], "This is your first true scouting quest.", "Scout's Wage", ["/give @p compass 1", "/give @p cooked_beef 10", "/give @p torch 16"]),
      q("Milestone Marker", "A road becomes trustworthy when Danita can read it at a glance.", ["Find 1 fork, bend, or important point on one of your travel routes.", "Build 1 road marker, signpost, cairn, or torch pillar there.", "Label or visually point toward at least 2 destinations.", "Make the marker at least 4 blocks tall or light it with at least 4 torches or lanterns."], "Use signs, banners, colored blocks, or different torch heights. Good route language saves lives when you are returning hurt.", "Road Sign Cache", ["/give @p oak_sign 4", "/give @p torch 12", "/give @p cobblestone 16"]),
      q("Trial by Bow", "A wise fighter kills from range whenever possible.", ["Bring 1 bow or crossbow and at least 24 arrows.", "Fight hostile mobs from at least 8 blocks away instead of rushing into melee.", "Defeat at least 5 enemies this way.", "Return with 8 arrows left or clear proof you kept control of the fight."], "Skeletons, zombies in open terrain, and creepers at distance are good targets.", "Archer's Due", ["/give @p bow 1", "/give @p arrow 24"]),
      q("Bullseye Mark", "The frontier rewards a steady hand and a patient shot.", ["Craft or place 1 target block or choose 1 marked block as a target.", "Stand at least 30 blocks away.", "Hit the target with an arrow or crossbow bolt.", "Return with the bow or crossbow stored in the armory."], "This is inspired by Bullseye. A target block is crafted with hay and redstone; shoot from a measured distance until the hit lands.", "Marksman's Prize", ["/give @p target 1", "/give @p arrow 32", "/give @p emerald 3"]),
      q("Tower Signal", "A marked lookout turns wilderness into known frontier.", ["Travel to a hill, ridge, or visible landmark at least 100 blocks from town.", "Build a signal marker at least 6 blocks tall with 1 campfire or 4 torches.", "Make the location visible from at least 40 blocks away.", "Return to town alive."], "This helps future journeys feel like part of an expanding road network.", "Beaconer's Kit", ["/give @p torch 16", "/give @p campfire 2", "/give @p cobblestone 16"]),
      q("Crypt Cleanse", "Dangerous hollows near the town should be cleared before they fester.", ["Find 1 cave pocket, dungeon, ruin, or hostile site within a safe route of town.", "Enter prepared with 10 food items, 16 torches, and 1 marked retreat route.", "Defeat at least 6 hostile mobs or loot 1 chest.", "Return alive with the area no longer an immediate menace."], "Do not go deeper than you can safely escape.", "Delver's Reward", ["/give @p iron_ingot 12", "/give @p bread 10", "/give @p torch 16"]),
      q("Protect the Villagers", "The strong are measured by who survives under their watch.", ["Count or confirm the villagers you intend to protect before nightfall.", "Light the villager district and close obvious entry gaps.", "Stay in or near the village through the night.", "Kill hostile mobs threatening the area.", "Confirm the villagers survive until morning."], "Think of this as a full night defense quest.", "Guardian's Mark", ["/give @p shield 1", "/give @p emerald 3", "/give @p bread 12"]),
      q("Saddle the Frontier", "Search for safer, longer travel and the means to ride it.", ["Travel at least 600 blocks in the main direction you expect future expansion.", "Search for 1 road line, mount source, village, or travel advantage.", "Bring back 1 gain for the stable or road network, such as a saddle, horse location, hay, or route marker.", "Mark the route with at least 3 signs, pillars, or torches for later return."], "This can be about route scouting as much as the mount itself.", "Rider's Due", ["/give @p saddle 1", "/give @p hay_block 8"]),
      q("Best Friends Forever", "A lonely road is safer when Danita earns a companion.", ["Tame 1 wolf, cat, horse, donkey, mule, parrot, or other tameable animal.", "Bring the companion back within 50 blocks of the settlement.", "Build or assign 1 safe resting place for it.", "Feed, sit, stable, or secure the companion before night."], "This is based on Best Friends Forever. Wolves use bones, cats use raw fish, and horses require repeated mounting until hearts appear.", "Companion's Bond", ["/give @p bone 12", "/give @p cooked_beef 12", "/give @p diamond_horse_armor 1"]),
      q("The Monstrous Shore", "Coasts promise wealth and ambush in equal measure.", ["Travel to 1 river mouth, coast, or ocean edge.", "Survive at least 1 shoreline danger, such as drowned, distance, cliffs, or nightfall.", "Bring back 8 fish, 1 treasure item, or coordinates for 1 harbor location.", "Return with at least 2 notes, signs, or markers to justify future harbor work."], "This is a scouting-and-survival shoreline quest.", "Mariner's Purse", ["/give @p cooked_cod 8", "/give @p oak_boat 1", "/give @p compass 1"]),
      q("The Ferry Point", "A river crossing is safer when the boat waits where it should.", ["Choose a useful river, lake, or coast route that Danita uses more than once.", "Build a small boat station, mooring post, dock notch, or ferry sign.", "Store at least one boat and basic supplies there.", "Mark the route back toward town from the water."], "Keep the boat station simple but visible. A chest, sign, lantern, and spare boat can turn a confusing shore into a reliable route.", "Ferry Keeper's Stock", ["/give @p oak_boat 2", "/give @p lantern 2", "/give @p barrel 1"]),
      q("Pale Garden Foray", "Eerie woods test the nerve more than the blade.", ["Prepare 10 food items, 16 torches, and at least 4 route markers.", "Travel into 1 eerie or dangerous forest region.", "Gather 16 pale, eerie, or rare materials from the trip.", "Return to base alive with route knowledge."], "This is a fear-and-discipline quest, not a full conquest.", "Forester's Oath", ["/give @p lantern 4", "/give @p cooked_beef 10", "/give @p ender_pearl 1"]),
      q("Nether Supply Run", "The Nether gives much, but only to those who return alive.", ["Prepare 12 food items, 8 gold ingots or 1 gold armor piece, and 1 clear retreat plan.", "Enter the Nether and secure the immediate 9 by 9 block portal area.", "Gather at least 32 useful Nether supplies.", "Return to the Overworld alive and store the full haul."], "Do not turn this into a sightseeing trip. Secure, gather, leave.", "Emberrunner's Prize", ["/give @p potion{Potion:\"minecraft:fire_resistance\"} 1", "/give @p gold_ingot 16", "/give @p cooked_beef 12"]),
      q("Return to Sender", "A ghast's fire can be turned back by a calm hand.", ["Enter the Nether with 12 food items and a clear portal route.", "Find 1 ghast at a safe distance from lava if possible.", "Deflect or shoot back at least 1 fireball, or defeat the ghast from range.", "Return to the Overworld alive."], "This is inspired by Return to Sender. You can punch a ghast fireball back, but using a bow from cover is safer if timing is difficult.", "Ghast-Hunter's Prize", ["/give @p ghast_tear 3", "/give @p fire_charge 8", "/give @p crying_obsidian 2"]),
      q("Trial Chamber Entry", "The old chambers of trial do not reveal themselves to wanderers for free.", ["Find or secure a cartographer villager.", "Trade with the cartographer until explorer maps become available.", "Buy a map that leads you toward a Trial Chamber.", "Follow the map and locate the chamber.", "Enter it and survive at least one real chamber encounter.", "Return with loot or route knowledge."], "Treat this like a guided dungeon expedition, not blind underground wandering.", "Chamber Delver's Cache", ["/give @p arrow 32", "/give @p shield 1", "/give @p golden_carrot 6"]),
      q("Breeze Hunter", "Learn to fight an enemy that wins through motion and pressure.", ["Enter a Trial Chamber with 1 shield, 1 ranged weapon, 24 arrows, and 12 food items.", "Engage at least 1 breeze.", "Survive the encounter without being knocked into a second uncontrolled fight.", "Leave with 1 chamber loot item or a marked safe retreat route."], "Movement discipline matters more here than brute force.", "Windbreaker's Fee", ["/give @p crossbow 1", "/give @p arrow 24"]),
      q("Wolf-Guard Patrol", "A loyal beast turns a road into a shared burden.", ["Bring 1 wolf companion on a patrol or expedition.", "Stay within 12 blocks of the wolf during combat.", "Defeat at least 4 hostile mobs while keeping the companion alive.", "Return to the settlement together."], "This quest is about controlled fighting, not reckless swarming.", "Houndguard's Share", ["/give @p bone 10", "/give @p cooked_beef 8", "/give @p armadillo_scute 4"]),
      q("Raid Captain Intercept", "Better to cut the trouble down on the road than at the gate.", ["Search for an illager patrol, outpost threat, or dangerous raiding presence.", "Engage away from the town itself.", "Defeat the threat without dragging disaster back home.", "Return with spoils or proof of the interception."], "This is preemptive defense, not reactive defense.", "Banner-Taker's Prize", ["/give @p crossbow 1", "/give @p arrow 24", "/give @p emerald 3"]),
      q("Ruins Under Sand", "Ancient places often sleep lightly.", ["Prepare 1 brush, 10 food items, and 16 torches.", "Travel to 1 desert ruin zone, trail ruin, or similar archaeology region.", "Stay alive while searching at least 1 structure or dig site.", "Recover 1 relic, shard, or clue.", "Return alive with the find."], "This is half archaeology, half expedition survival.", "Dustwalker's Reward", ["/give @p brush 1", "/give @p bread 10", "/give @p torch 16"]),
      q("Ocean Ruin Sweep", "Waterlogged danger still counts as danger.", ["Prepare 8 food items and 1 water-breathing potion if possible.", "Travel to 1 ocean ruin or dangerous shoreline structure.", "Search or fight until you secure 1 loot item or map-confirmed location.", "Return alive with treasure or coordinates for the location."], "This works best as a careful dive, not a reckless underwater brawl.", "Diver's Wage", ["/give @p potion{Potion:\"minecraft:water_breathing\"} 1", "/give @p cooked_cod 8", "/give @p emerald 2"]),
      q("Happy Ghast Prospect", "Strange frontiers and stranger futures open to the brave.", ["Prepare 12 food items, 1 fire resistance potion, and 16 building blocks for a specialty Nether or sky-linked run.", "Pursue 1 material or clue tied to that future progression.", "Keep the trip under 1 controlled route with a marked return path.", "Return with 1 gain stored safely at home."], "This is a rare-opportunity scouting quest, not a full late-game commitment.", "Netherfarer's Purse", ["/give @p ghast_tear 2", "/give @p fire_charge 6", "/give @p ender_pearl 2"]),
      q("Ominous Reckoning", "Some victories should only be sought when one is truly prepared.", ["Bring 16 strong food items, iron armor or better, and 32 arrows.", "Trigger or enter 1 ominous-style challenge only when ready.", "Survive the event without a reckless death.", "Return with 1 reward, loot item, or proof of victory."], "This should feel like an earned challenge, not routine farming.", "Reckoner's Chest", ["/give @p diamond 1", "/give @p golden_carrot 8", "/give @p arrow 32"]),
      q("Deep Dark Nerve Test", "Below the world, noise is the real enemy.", ["Prepare 16 food items, 32 wool, and 1 fast escape route.", "Reach 1 Deep Dark area.", "Search for signs of an Ancient City or 1 sculk-heavy zone.", "Loot 1 prize or mark the route with at least 4 safe markers.", "Return alive."], "This is a stealth-and-discipline quest more than a combat quest.", "Shadowrunner's Fee", ["/give @p white_wool 16", "/give @p torch 16", "/give @p diamond 1"]),
      q("Sneak Discipline", "In deep places, silence is stronger than armor.", ["Bring at least 32 wool and 12 food items.", "Enter a sculk or Deep Dark area.", "Sneak or place wool past at least 3 sculk sensors or shriekers without triggering a disaster.", "Return alive with 1 sculk sample or a marked safe path."], "This is inspired by stealth-focused Deep Dark play. Walk slowly, crouch near sensors, place wool to block vibrations, and leave before greed gets loud.", "Silent-Step Reward", ["/give @p white_wool 32", "/give @p sculk_sensor 2", "/give @p diamond 2"]),
      q("Ancient Preparation", "Courage without planning is just a quick grave.", ["Build 1 full expedition loadout with 16 food items, 8 golden carrots, 2 ender pearls, and 32 escape blocks.", "Scout or begin 1 very dangerous destination.", "Avoid overcommitting if armor durability drops below half or food drops below 8 items.", "Return with route knowledge or 1 meaningful prize."], "This is a ready yourself for late-game danger quest.", "Expeditioner's Treasury", ["/give @p cooked_beef 16", "/give @p golden_carrot 8", "/give @p ender_pearl 2"]),
      q("Mansion Rumor", "Rumors of a dark manor spread through the villages.", ["Find or secure a cartographer villager.", "Trade with the cartographer until explorer maps become available.", "Buy a Woodland Mansion map.", "Follow the map until you visually confirm the mansion.", "Mark the route with a note, outpost, or map record.", "Return alive. You do not need to clear the mansion yet."], "This is a discovery quest, not a conquest quest.", "Pathfinder's Commission", ["/give @p map 1", "/give @p compass 1", "/give @p emerald 4"]),
      q("Creaking Heart Hunt", "In the Pale Garden, the creature is not the true target.", ["Enter the Pale Garden at the time when the danger is active.", "Search the pale trees for the source of the threat.", "Find the heart block that sustains the danger.", "Destroy the source instead of wasting effort on endless fighting.", "Return with pale materials, resin, or route proof."], "Focus on the source, not just the monster.", "Heartbreaker's Prize", ["/give @p diamond 4", "/give @p lantern 8", "/give @p ender_pearl 4", "/give @p resin_block 8"]),
      q("Road to the End", "All roads of legend eventually point toward the dragon.", ["Gather 4 ender pearls and 4 blaze powder for Eyes of Ender.", "Craft at least 1 Eye of Ender.", "Throw 1 eye and follow the direction it gives for at least 500 blocks or until the route changes.", "Mark the route with at least 4 markers or establish 1 outpost along the line.", "Return alive after confirming the stronghold direction."], "This quest is about beginning the path to the End, not finishing it.", "Dragonroad Provision", ["/give @p ender_pearl 4", "/give @p blaze_powder 4", "/give @p golden_carrot 8"]),
      q("Dragon Preparations", "Before the End opens, Danita must gather courage into one final war chest.", ["Build or claim 1 staging room for the End expedition.", "Fill 1 dedicated chest with 16 strong food items, 64 blocks, 32 arrows, 4 pearls, 12 bottles, 1 spare weapon, and 1 spare pickaxe.", "Place at least 1 bed, 2 signs, or 2 notes nearby so the plan is clear before leaving.", "Leave the town with 16 backup food items and 32 backup blocks so defeat would not end the whole story."], "Do this before hunting the dragon, not while rushing to the portal. Slow preparation is the difference between adventure and panic.", "Dragon War Chest", ["/give @p arrow 64", "/give @p golden_carrot 24", "/give @p ender_pearl 8", "/give @p diamond 6"])
    ]
  }
};

function q(title, description, objectives, hint, reward, commands) {
  return { title, description, objectives, hint, reward, commands };
}
